export const GRADIENT_BY_ID = Object.fromEntries(GRADIENTS.map(g => [g.id, g]));

export function isGradientId(id) {
  return typeof id === "string" && Object.prototype.hasOwnProperty.call(GRADIENT_BY_ID, id);
}
